solutions.python:
class Solution:
    def smallerNumbersThanCurrent(self, nums):
        freq = [0] * 102
        for v in nums:
            freq[v] += 1
        prefix = [0] * 102
        for i in range(1, 102):
            prefix[i] = prefix[i - 1] + freq[i - 1]
        return [prefix[v] for v in nums]

solutions.javascript:
var smallerNumbersThanCurrent = function(nums) {
    const freq = new Array(102).fill(0);
    for (const v of nums) freq[v]++;
    const prefix = new Array(102).fill(0);
    for (let i = 1; i < 102; i++) prefix[i] = prefix[i - 1] + freq[i - 1];
    return nums.map(v => prefix[v]);
};
